import java.io.*;
import java.util.Scanner;

public class SecureCommandExecution {
    public static void main(String[] args) {
        try {
            Scanner scanner = new Scanner(System.in);
            System.out.print("Enter a directory name: ");
            String input = scanner.nextLine();

            // Validate user input to ensure it contains only valid characters
            if (!input.matches("[a-zA-Z0-9_/-]+")) {
                System.out.println("Invalid directory name. Please enter a valid name.");
                return;
            }

            // Securely construct the command using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder();
            processBuilder.command("ls", input);

            Process process = processBuilder.start();

            BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = outputReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

